parameters.jsCode:
const raw = $input.first().json.output || '';

try {
  const inicio = raw.indexOf('{');
  const fin = raw.lastIndexOf('}') + 1;
  if (inicio === -1 || fin === 0) throw new Error('No JSON');

  const parsed = JSON.parse(
    raw.substring(inicio, fin).replace(/[\n\r]/g, ' ')
  );

  return [{
    json: {
      nombre: parsed.nombre || null,
      correo: parsed.correo || null,
      telefono: parsed.telefono || null,
      transferir_agente: parsed.transferir_agente ?? 0,
      response: parsed.response || ''
    }
  }];
} catch(e) {
  return [{
    json: {
      nombre: null,
      correo: null,
      telefono: null,
      transferir_agente: 1,
      response: raw
    }
  }];
}
